-- WARNING: This script will delete ALL data from the specified tables.
-- Use with extreme caution, especially in production environments.

-- Delete existing data from dependent tables first to avoid foreign key constraints
DELETE FROM user_reactions WHERE TRUE;
DELETE FROM reports WHERE TRUE;
DELETE FROM posts WHERE TRUE; -- Delete posts before categories/users
DELETE FROM category_moderators WHERE TRUE; -- Depends on users and categories
DELETE FROM category_follows WHERE TRUE; -- Depends on users and categories
DELETE FROM email_confirm_tokens WHERE TRUE; -- Depends on users
DELETE FROM avatars WHERE TRUE; -- Depends on users
DELETE FROM users_roles WHERE true; -- Depends on users and roles

-- Delete data from core tables
DELETE FROM roles WHERE true;
DELETE FROM categories WHERE TRUE;
DELETE FROM users WHERE true;

-- Reset sequences/identity columns if necessary (syntax varies by database, e.g., for PostgreSQL)
-- Setting sequences to start after the highest manually inserted ID + 1
SELECT setval('users_seq', 101, true); -- We are inserting up to user ID 100
SELECT setval('categories_id_seq', 1001, true); -- Assuming categories were up to 12, setting high for future
SELECT setval('user_reactions_id_seq', 101, true); -- Setting high after user IDs
SELECT setval('reports_id_seq', 101, true); -- Setting high after user IDs
SELECT setval('category_follows_id_seq', 501, true); -- Setting high after manual follows inserts
SELECT setval('category_moderators_id_seq', 201, true); -- Setting high after manual moderators inserts
SELECT setval('avatars_id_seq', 101, true); -- Setting high after avatar inserts
SELECT setval('posts_id_seq', 16, true); -- Original script inserted posts up to ID 15

-- Insert base roles
INSERT INTO roles (id, name) VALUES (1, 'ROLE_USER');
INSERT INTO roles (id, name) VALUES (2, 'ROLE_MODERATOR');

