INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('Latest Breakthroughs in AI', 'Let''s discuss the recent advancements in Artificial Intelligence, especially in machine learning and neural networks.', 0, 'DISCUSSION', '2023-09-17 19:27:37', '2024-11-02 13:08:04', 1, 1),
                                                                                                        ('Review of the New Action RPG', 'Just finished playing the latest action RPG and wanted to share my thoughts. What did you guys think?', 0, 'DISCUSSION', '2025-01-28 09:20:43', '2025-01-28 15:44:28', 2, 2),
                                                                                                        ('The Physics Behind Black Holes', 'Trying to understand the complex physics involved in black holes. Any experts here?', 0, 'QUESTION', '2023-12-23 04:21:50', '2024-10-20 14:37:43', 3, 3),
                                                                                                        ('Best Practices for Python Development', 'Sharing some tips and tricks I''ve learned for writing clean and efficient Python code.', 0, 'DISCUSSION', '2023-12-10 17:04:40', '2024-10-23 06:10:29', 4, 4),
                                                                                                        ('Showcase Your Digital Art', 'Post your latest digital art creations here! Looking for inspiration.', 0, 'DISCUSSION', '2023-06-16 11:23:23', '2025-03-10 20:15:27', 5, 5),
                                                                                                        ('Favorite Albums of All Time', 'Let''s talk about those albums that never get old. What are your timeless classics?', 0, 'DISCUSSION', '2024-09-29 01:19:12', '2024-11-09 15:08:55', 6, 6),
                                                                                                        ('Upcoming Sci-Fi Movies', 'Excited about the new sci-fi releases? Which ones are you most looking forward to?', 0, 'DISCUSSION', '2024-07-13 13:03:25', '2025-01-09 01:00:45', 7, 7),
                                                                                                        ('Recommendations for Fantasy Novels', 'Looking for a new fantasy series to dive into. Any hidden gems?', 0, 'QUESTION', '2023-10-02 06:57:14', '2024-08-16 05:32:56', 8, 8),
                                                                                                        ('Easy Weeknight Dinner Recipes', 'Share your go-to recipes for quick and tasty dinners during the week.', 0, 'DISCUSSION', '2024-02-09 05:30:57', '2024-09-14 06:27:13', 9, 9),
                                                                                                        ('Backpacking Through Southeast Asia', 'Anyone planning a trip or have experiences to share about backpacking in Southeast Asia?', 0, 'DISCUSSION', '2023-07-12 16:23:25', '2024-03-18 15:49:10', 10, 10),
                                                                                                        ('Training for a Marathon', 'Tips, advice, and motivation needed for training for my first marathon!', 0, 'QUESTION', '2023-02-15 17:34:53', '2023-07-03 16:27:24', 11, 11),
                                                                                                        ('Mindfulness Techniques for Stress Reduction', 'Discussing effective mindfulness practices to help manage stress.', 0, 'DISCUSSION', '2024-06-02 18:36:06', '2024-07-23 15:32:15', 12, 12),
                                                                                                        ('Latest JavaScript Frameworks', 'What are your thoughts on the newest JavaScript frameworks and libraries?', 0, 'DISCUSSION', '2023-05-08 02:40:12', '2025-03-12 11:35:59', 13, 1),
                                                                                                        ('Best Indie Games of the Year', 'Highlighting some amazing independent games released recently.', 0, 'DISCUSSION', '2024-08-04 15:05:37', '2024-10-18 00:36:05', 1, 2),
                                                                                                        ('The Ethics of Gene Editing', 'A complex topic with many viewpoints. Let''s have a respectful discussion.', 0, 'DISCUSSION', '2024-03-24 18:19:49', '2024-09-17 21:05:20', 2, 3);


INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('How do you stay productive while working remotely?', 'I recently transitioned to full-time remote work and I’m struggling to maintain focus. What routines or tools have worked best for you?', 0, 'QUESTION', '2025-03-15 05:49:52', '2025-04-01 15:25:56', 12, 3),
                                                                                                        ('The rise of AI: Threat or opportunity?', 'With AI tools becoming more integrated into everyday life, I’m curious about how people view their impact on jobs and creativity.', 0, 'DISCUSSION', '2025-04-12 15:48:27', '2025-04-14 13:13:21', 27, 4),
                                                                                                        ('What’s the best book you’ve read this year?', 'Looking to expand my reading list. I enjoy fiction, biographies, and anything with a strong narrative. Recommendations?', 0, 'QUESTION', '2025-04-12 13:47:59', '2025-04-18 02:16:15', 8, 2),
                                                                                                        ('Why learning to code changed my career path', 'Just wanted to share a bit about how picking up coding in my spare time led me to leave my sales job and land a dev role.', 0, 'DISCUSSION', '2025-03-29 14:25:13', '2025-04-11 12:51:53', 45, 1),
                                                                                                        ('Should universities rethink grading systems?', 'There’s growing debate around the effectiveness of traditional grading. Are alternative assessments the future of education?', 0, 'QUESTION', '2025-04-14 07:00:46', '2025-04-29 20:23:27', 33, 5),
                                                                                                        ('I quit social media for 30 days. Here’s what I learned.', 'As an experiment, I removed all social media apps from my phone for a month. The results surprised me more than I expected.', 0, 'DISCUSSION', '2025-03-16 03:02:34', '2025-03-19 08:42:22', 19, 6),
                                                                                                        ('How to deal with burnout in creative work?', 'I love what I do but lately I’ve felt completely drained and uninspired. How do you recharge your creative energy?', 0, 'QUESTION', '2025-03-20 20:50:15', '2025-04-27 22:50:36', 14, 2),
                                                                                                        ('Why community matters in online learning', 'As someone taking online courses, I’ve realized how important it is to have a support system or forum to discuss ideas.', 0, 'DISCUSSION', '2025-04-15 05:24:41', '2025-04-24 22:55:49', 22, 3),
                                                                                                        ('Is remote collaboration killing innovation?', 'Some argue that the lack of physical presence limits spontaneous idea generation. What do you think?', 0, 'QUESTION', '2025-04-25 03:10:13', '2025-04-27 04:41:29', 9, 4),
                                                                                                        ('My journey from beginner to full-stack developer', 'Two years ago I didn’t know how to write a line of code. Now I’ve built several web apps and just got hired. Here’s what helped me most.', 0, 'DISCUSSION', '2025-03-27 11:24:44', '2025-04-06 21:35:26', 41, 1);

INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('How do I improve my time management skills?', 'Ive been struggling with time management recently. I often find myself procrastinating and not being able to focus on tasks for long. Any tips on how I can improve my time management and be more productive throughout the day?', 0, 'QUESTION', '2025-03-06 06:23:02', '2025-04-19 21:47:03', 1, 1),
                                                                                                        ('What are the best ways to stay motivated while working from home?', 'Working from home has its perks, but staying motivated is definitely a challenge. I tend to get distracted easily by household chores, social media, and other things. How do you manage to stay productive and focused while working from home?', 0, 'QUESTION', '2025-02-28 16:44:12', '2025-04-20 03:56:37', 2, 2),
                                                                                                        ('How to balance work and personal life in a remote job?', 'Ive recently started working remotely, and its been a challenge to find a balance between my work and personal life. The lines between the two seem to blur, and I end up working late into the evening. Any advice on how to create a clear boundary between work and personal time?', 0, 'QUESTION', '2025-02-19 08:29:18', '2025-03-25 23:51:18', 3, 3),
                                                                                                        ('Can anyone recommend a good book on productivity?', 'Ive been trying to read more about productivity to help me stay focused and organized. Does anyone have any recommendations for a good book on productivity or personal development? Something practical and easy to follow would be great!', 0, 'QUESTION', '2025-03-18 13:59:34', '2025-05-01 04:36:59', 4, 4),
                                                                                                        ('What are your thoughts on setting daily goals?', 'Ive been trying to set daily goals to stay on track and be more productive. However, I often feel overwhelmed by the number of things I need to do. How do you approach setting realistic and achievable daily goals?', 0, 'QUESTION', '2025-04-13 00:04:51', '2025-05-03 02:22:30', 5, 5),
                                                                                                        ('What is the best way to handle burnout at work?', 'Lately, Ive been feeling completely burnt out at work. The stress and long hours are starting to take a toll on my mental health. What are some strategies or tips to manage burnout and regain energy and motivation?', 0, 'QUESTION', '2025-04-21 06:45:45', '2025-04-29 22:46:27', 6, 6),
                                                                                                        ('How do you avoid distractions when working on a project?', 'Im currently working on a large project, but I keep getting distracted by things around me. Whether its checking social media or getting up to do other things, I cant seem to stay focused. Any tips for minimizing distractions and staying on task?', 0, 'QUESTION', '2025-03-04 01:11:07', '2025-04-27 00:10:12', 7, 7),
                                                                                                        ('How do you deal with procrastination?', 'I tend to procrastinate a lot, especially when it comes to tasks that seem overwhelming or boring. Its becoming a habit, and I want to break it. What are some effective strategies to overcome procrastination and get things done on time?', 0, 'QUESTION', '2025-03-15 15:15:13', '2025-03-28 14:09:56', 8, 8),
                                                                                                        ('What is the most productive time of day for you?', 'Ive heard that some people are more productive in the morning, while others do their best work in the afternoon or evening. When is the best time of day for you to be most productive, and do you have any tips for optimizing your workflow during that time?', 0, 'QUESTION', '2025-02-09 00:28:38', '2025-02-10 14:43:22', 9, 9),
                                                                                                        ('How do you maintain a healthy work-life balance?', 'Finding a healthy work-life balance has always been a challenge for me. I often end up working overtime, which leaves little time for relaxation or personal activities. How do you make sure to prioritize both work and personal time?', 0, 'QUESTION', '2025-02-07 16:24:19', '2025-02-16 20:36:01', 10, 10);

INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('The importance of setting boundaries in a remote job', 'In remote work environments, setting boundaries can be challenging. Often, the line between personal time and work time becomes blurry, leading to burnout and stress. I believe its crucial to set clear boundaries with both yourself and your colleagues. What are some of the boundaries youve set to protect your work-life balance?', 0, 'DISCUSSION', '2025-03-31 07:04:56', '2025-04-16 14:15:40', 11, 1),
                                                                                                        ('How do you deal with unexpected changes in plans?', 'Its frustrating when plans change unexpectedly. Whether its a last-minute work deadline or a personal issue, it can throw off your whole schedule. Ive been trying to adjust better to these changes and not let them ruin my day. How do you handle unexpected changes or disruptions in your plans?', 0, 'DISCUSSION', '2025-03-20 23:53:29', '2025-04-15 12:51:48', 12, 2),
                                                                                                        ('Tips for improving productivity during meetings', 'Meetings can often feel like a waste of time, especially when they run too long or lack focus. Ive started using a few strategies to make meetings more productive, like setting clear agendas and keeping track of time. How do you ensure meetings stay focused and efficient?', 0, 'DISCUSSION', '2025-02-26 22:22:18', '2025-03-20 23:27:56', 13, 3),
                                                                                                        ('How to manage multiple projects at once?', 'Handling multiple projects simultaneously can be stressful, but its often part of the job. Ive been using a project management tool to stay organized, but its still tough to juggle everything. What techniques or tools do you use to manage multiple projects and stay on top of deadlines?', 0, 'DISCUSSION', '2025-03-21 08:11:42', '2025-04-07 03:41:18', 14, 4),
                                                                                                        ('How do you prioritize tasks effectively?', 'I often struggle with knowing what tasks to prioritize, especially when everything seems urgent. Ive tried using to-do lists and scheduling, but its still difficult to know where to start. What methods or systems do you use to prioritize your daily tasks?', 0, 'DISCUSSION', '2025-05-06 02:24:12', '2025-05-07 10:37:28', 15, 5),
                                                                                                        ('The role of mindfulness in staying productive', 'I recently started practicing mindfulness techniques, and Ive noticed a positive impact on my ability to stay focused and productive. By taking short breaks to refocus and breathe, I feel more energized throughout the day. Has mindfulness played a role in your productivity? If so, how do you incorporate it into your routine?', 0, 'DISCUSSION', '2025-04-29 19:15:28', '2025-05-02 11:20:11', 16, 6),
                                                                                                        ('Do you think multitasking is effective?', 'Ive heard mixed opinions about multitasking. Some believe it helps get more done in less time, while others argue it leads to decreased quality and focus. Personally, I feel like multitasking doesnt always work well for me. What are your thoughts on multitasking? Do you find it effective?', 0, 'DISCUSSION', '2025-04-20 09:29:44', '2025-05-04 05:08:01', 17, 7),
                                                                                                        ('How to stay motivated during long-term projects', 'Long-term projects can feel overwhelming, especially when the end goal is far off. I often lose motivation and struggle to keep my energy up over time. Ive tried breaking the project into smaller goals, but its still tough. How do you stay motivated when working on something that takes months or years to complete?', 0, 'DISCUSSION', '2025-04-25 20:25:33', '2025-04-28 11:15:59', 18, 8),
                                                                                                        ('The impact of physical health on productivity', 'Ive started paying more attention to my physical health lately, and Ive noticed it has a direct impact on my productivity. Regular exercise and eating healthy seem to give me more energy and focus throughout the day. How do you feel your physical health affects your work and productivity?', 0, 'DISCUSSION', '2025-02-25 05:21:42', '2025-05-06 11:59:42', 19, 9),
                                                                                                        ('How do you handle criticism at work?', 'Receiving criticism can be tough, but I try to view it as an opportunity for growth. Its not always easy, though, and I often feel defensive. How do you cope with constructive criticism? Do you have any strategies for accepting feedback and improving?', 0, 'DISCUSSION', '2025-04-12 09:30:25', '2025-04-22 11:59:52', 20, 10);
INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('How to deal with procrastination in a remote job', 'Procrastination seems to be a bigger issue when working remotely. Without the structure of an office, its easy to get distracted. Ive been trying to break tasks into smaller chunks and give myself rewards when completing them. What strategies do you use to combat procrastination while working from home?', 0, 'DISCUSSION', '2025-04-12 15:16:32', '2025-05-03 06:59:55', 21, 1),
                                                                                                        ('The importance of setting boundaries with clients', 'When working with clients, its easy to blur the line between professional and personal time. Ive learned the hard way that setting clear boundaries is crucial for maintaining my work-life balance. How do you manage client expectations and ensure boundaries are respected?', 0, 'DISCUSSION', '2025-01-09 13:13:52', '2025-01-17 09:13:27', 22, 2),
                                                                                                        ('How do you overcome writer''s block?', 'As a writer, I often face the dreaded writer''s block. It feels frustrating when I know what I want to write, but the words just wont come out. Ive found that taking short breaks and letting my mind wander helps. What strategies do you use to overcome writer''s block?', 0, 'DISCUSSION', '2025-04-28 02:24:50', '2025-05-04 20:40:13', 23, 3),
                                                                                                        ('Best practices for maintaining a healthy work-life balance', 'Maintaining a work-life balance is something I constantly struggle with. Between work, personal life, and everything else, it feels like theres always something demanding my attention. How do you make sure to carve out time for yourself, especially when things get hectic?', 0, 'DISCUSSION', '2025-03-05 15:31:39', '2025-03-25 19:01:46', 24, 4),
                                                                                                        ('What''s your approach to handling difficult colleagues?', 'I think everyone has encountered difficult colleagues at some point. Whether its a lack of communication or conflicting work styles, it can really impact productivity. I try to address the issue directly and professionally. How do you handle difficult colleagues at work?', 0, 'DISCUSSION', '2025-02-17 06:26:14', '2025-03-29 22:20:40', 25, 5),
                                                                                                        ('The impact of a clean workspace on productivity', 'Ive noticed that a cluttered workspace can make it difficult to focus. Ive been working on keeping my desk tidy, and I feel like its helped improve my productivity. Do you believe a clean workspace impacts your work? How do you keep your workspace organized?', 0, 'DISCUSSION', '2025-01-17 11:32:44', '2025-02-03 12:15:32', 26, 6),
                                                                                                        ('How do you stay organized when juggling many tasks?', 'I find it hard to stay on top of everything when I have multiple tasks to manage. I use apps and to-do lists to track everything, but it still feels overwhelming at times. What methods or tools do you use to stay organized and ensure nothing falls through the cracks?', 0, 'DISCUSSION', '2025-03-28 14:12:57', '2025-04-21 16:56:03', 27, 7),
                                                                                                        ('How do you handle stress during high-pressure projects?', 'Stress can be overwhelming when working on high-pressure projects, and sometimes it feels like there’s no time to relax. I try to break the project into smaller tasks and take breaks, but it’s still challenging. How do you manage stress during these types of projects?', 0, 'DISCUSSION', '2025-01-08 00:25:18', '2025-01-28 11:49:09', 28, 8),
                                                                                                        ('The role of feedback in professional growth', 'Feedback is essential for growth, but it can sometimes be difficult to accept, especially if it''s critical. Ive learned to take a step back and view feedback as an opportunity to improve. How do you handle feedback in your career? Do you find it helpful?', 0, 'DISCUSSION', '2025-01-14 19:13:42', '2025-03-21 18:49:41', 29, 9),
                                                                                                        ('How do you stay motivated during routine tasks?', 'Sometimes the most routine tasks can feel monotonous and demotivating. I try to remind myself of the bigger picture and how even the smallest task can make a difference. What strategies do you use to stay motivated during routine or repetitive tasks?', 0, 'DISCUSSION', '2025-04-05 15:02:35', '2025-04-26 00:51:14', 30, 10);

INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('How to break bad habits and form new ones', 'Breaking a bad habit and forming a new one can feel like an uphill battle. I’ve tried a few different strategies, such as tracking progress and rewarding myself when I achieve small milestones. Has anyone found success with any specific techniques or habits that helped them change their behavior for the better?', 0, 'DISCUSSION', '2025-01-11 05:31:46', '2025-02-05 08:20:14', 13, 3),
                                                                                                        ('The importance of time management in personal development', 'I’ve noticed that good time management is key to personal growth. I’ve been working on blocking out distractions and scheduling my day more effectively. What techniques do you use to manage your time and make room for self-improvement?', 0, 'DISCUSSION', '2025-02-07 16:48:13', '2025-04-16 08:31:17', 5, 6),
                                                                                                        ('How to stay motivated to learn new skills', 'Learning new skills can be tough, especially when life gets busy. I’ve been setting small goals to stay motivated, and it’s been helping me keep going. How do you stay motivated when learning something new, especially if it feels overwhelming?', 0, 'DISCUSSION', '2025-01-26 22:10:17', '2025-04-19 17:20:32', 14, 2),
                                                                                                        ('Is it possible to balance full-time work with side projects?', 'I’ve been thinking about taking on a side project while working full-time. I’m unsure how to balance the two and avoid burnout. If anyone has experience juggling both, I’d love to hear how you manage your time and energy effectively.', 0, 'DISCUSSION', '2025-01-03 02:29:24', '2025-01-03 08:02:42', 9, 4),
                                                                                                        ('How do you deal with failure in your career?', 'Failure can feel like a setback, but I’ve learned that it’s an opportunity for growth. I’ve tried to reframe failure as a learning experience, but it’s still tough sometimes. How do you deal with failure in your career and use it to improve yourself?', 0, 'DISCUSSION', '2025-04-18 04:38:34', '2025-04-26 22:27:49', 6, 1),
                                                                                                        ('What are your strategies for work-life integration?', 'Work-life integration seems like a more achievable goal than balance for me. I’ve been trying to mix personal activities with work, but it’s challenging to find a harmonious flow. What strategies do you use to integrate your personal and professional lives?', 0, 'DISCUSSION', '2025-02-22 15:15:08', '2025-03-12 18:19:00', 11, 3),
                                                                                                        ('How do you stay productive while working remotely?', 'Remote work offers great flexibility, but it can also lead to distractions and a lack of structure. I’ve found that having a set routine and dedicated workspace helps, but I’m curious to hear how others stay productive and motivated while working from home.', 0, 'DISCUSSION', '2025-03-24 05:22:50', '2025-04-16 19:43:21', 12, 2),
                                                                                                        ('The role of mentorship in career development', 'Having a mentor can make a huge difference in career development. I’ve been lucky to have a few mentors who guided me through key decisions. How has mentorship played a role in your career, and what qualities do you look for in a mentor?', 0, 'DISCUSSION', '2025-01-20 12:29:26', '2025-03-02 08:47:04', 4, 5),
                                                                                                        ('How do you handle burnout and prevent it from affecting your work?', 'Burnout is a real concern, especially in high-pressure environments. I’ve been trying to manage my workload better and take more breaks, but it’s still tough. What strategies do you use to avoid burnout and keep your work-life balance intact?', 0, 'DISCUSSION', '2025-04-01 00:46:12', '2025-04-03 04:39:59', 7, 6),
                                                                                                        ('What’s your experience with learning through online courses?', 'I’ve been taking a few online courses lately, but sometimes it’s hard to stay focused and motivated. I find that setting deadlines and engaging with a community helps, but I’m curious about how others approach learning through online platforms. What’s your experience with online education?', 0, 'DISCUSSION', '2025-01-19 10:50:28', '2025-04-12 02:39:34', 15, 8);



INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('How to handle difficult conversations at work', 'Difficult conversations at work can be a challenge, especially when dealing with conflicts or misunderstandings. I try to stay calm and listen first, but it’s not always easy. What strategies do you use to navigate difficult conversations professionally and effectively?', 0, 'DISCUSSION', '2025-04-11 03:09:10', '2025-04-30 06:26:29', 16, 7),
                                                                                                        ('What’s the best way to ask for feedback from colleagues?', 'Asking for feedback can feel intimidating, but it’s important for growth. I try to approach it in a constructive way, focusing on areas where I want to improve. How do you ask for feedback, and how do you respond to it without feeling discouraged?', 0, 'DISCUSSION', '2025-04-04 07:48:53', '2025-05-07 06:22:17', 17, 5),
                                                                                                        ('How to develop a growth mindset in the workplace', 'A growth mindset has been essential in helping me overcome challenges at work. I try to embrace challenges and view failures as learning opportunities. What techniques have helped you develop a growth mindset, and how has it influenced your career?', 0, 'DISCUSSION', '2025-02-16 04:37:02', '2025-04-23 17:32:17', 18, 2),
                                                                                                        ('What are the key habits of successful entrepreneurs?', 'I’ve been reading about successful entrepreneurs and the habits that set them apart. Many recommend focusing on consistency, time management, and staying motivated. What habits do you think are essential for success in business and entrepreneurship?', 0, 'DISCUSSION', '2025-01-27 14:31:31', '2025-01-31 09:19:05', 3, 1),
                                                                                                        ('How to prioritize personal development alongside career goals', 'Balancing personal development with career growth is tough, but I try to make time for both. Whether it’s reading, learning new skills, or focusing on mental health, it’s important to invest in both. How do you balance personal development with your career goals?', 0, 'DISCUSSION', '2025-02-04 10:42:01', '2025-04-08 03:13:52', 9, 4),
                                                                                                        ('How do you keep yourself accountable to your goals?', 'Staying accountable to my goals is something I struggle with sometimes. I’ve started sharing my goals with others and tracking my progress regularly. How do you stay accountable to your personal and professional goals?', 0, 'DISCUSSION', '2025-04-28 15:46:04', '2025-05-03 04:50:56', 5, 6),
                                                                                                        ('What’s your approach to networking in your industry?', 'Networking can be daunting, but it’s crucial for career advancement. I try to attend industry events and stay connected with people on LinkedIn. How do you approach networking, and what’s worked best for you in building meaningful connections?', 0, 'DISCUSSION', '2025-03-12 04:26:11', '2025-04-10 16:22:39', 8, 5),
                                                                                                        ('How do you handle stress during tight deadlines?', 'Deadlines can create a lot of pressure, and stress often follows. I’ve been using techniques like deep breathing and breaking tasks into smaller pieces to manage stress. What do you do to stay calm and focused during high-pressure situations?', 0, 'DISCUSSION', '2025-03-27 21:28:12', '2025-04-24 21:49:16', 19, 3),
                                                                                                        ('The importance of self-reflection in personal growth', 'Self-reflection has been an important part of my growth journey. I try to take time each week to reflect on my progress, mistakes, and what I can do better. How does self-reflection play a role in your personal development?', 0, 'DISCUSSION', '2025-02-19 18:36:52', '2025-03-08 14:24:15', 2, 6),
                                                                                                        ('What’s your experience with setting and achieving long-term goals?', 'Long-term goals are important, but they can feel overwhelming. I try to break them down into smaller, more manageable tasks. What strategies do you use to stay motivated and on track with your long-term goals?', 0, 'DISCUSSION', '2025-03-27 03:53:56', '2025-05-05 05:28:41', 10, 7),
                                                                                                        ('How do you manage expectations in both work and life?', 'Managing expectations in both work and life can be difficult, especially when it feels like there’s too much on your plate. I’ve been practicing saying no and setting clearer boundaries. How do you handle managing expectations from others while still taking care of yourself?', 0, 'DISCUSSION', '2025-04-04 08:12:00', '2025-05-04 20:00:03', 6, 3),
                                                                                                        ('What are some effective strategies for problem-solving?', 'Problem-solving skills are essential in any profession. I try to approach challenges step-by-step and gather input from others. What problem-solving strategies have worked well for you in your career or personal life?', 0, 'DISCUSSION', '2025-01-27 18:47:32', '2025-03-27 13:02:19', 14, 5),
                                                                                                        ('How do you stay motivated when working on long-term projects?', 'Long-term projects can sometimes feel like a grind, and staying motivated is key. I break down tasks into smaller milestones and celebrate small wins. How do you keep yourself motivated over the long haul?', 0, 'DISCUSSION', '2025-01-15 10:15:22', '2025-04-04 22:03:11', 3, 8),
                                                                                                        ('What are your thoughts on work culture and its impact on productivity?', 'The culture of a workplace can really influence how productive employees are. I’ve been in environments where the culture is empowering, and others where it’s more stifling. What’s your experience with work culture, and how does it affect your productivity and motivation?', 0, 'DISCUSSION', '2025-01-28 13:02:47', '2025-02-14 09:15:34', 11, 4),
                                                                                                        ('How do you deal with uncertainty in your career?', 'Uncertainty can be nerve-wracking, but I try to embrace it as a part of the journey. I focus on what I can control and try not to dwell on things I can’t. How do you deal with career uncertainty, and what steps do you take to stay grounded?', 0, 'DISCUSSION', '2025-04-29 18:06:57', '2025-05-04 00:59:55', 15, 6),
                                                                                                        ('How do you maintain focus when multitasking?', 'Multitasking is a skill I’ve been working on, but it’s challenging to stay focused on multiple things at once. I try to prioritize tasks and focus on one thing at a time when possible. How do you handle multitasking without losing focus?', 0, 'DISCUSSION', '2025-03-06 06:36:25', '2025-04-21 22:54:39', 18, 2),
                                                                                                        ('What tools or apps help you stay organized and productive?', 'I’ve been using a variety of tools to stay organized, like to-do lists, calendars, and project management apps. I find that having everything in one place helps me stay focused and on track. What tools do you use to stay organized and productive?', 0, 'DISCUSSION', '2025-05-04 00:50:34', '2025-05-06 22:45:34', 7, 1),
                                                                                                        ('What’s your approach to taking risks in your career?', 'Taking risks is a natural part of career growth, but it can be daunting. I try to calculate the potential risks and rewards before making big decisions. How do you approach risk-taking, and what’s your strategy for managing uncertainty?', 0, 'DISCUSSION', '2025-04-09 07:52:39', '2025-04-25 09:26:19', 13, 7),
                                                                                                        ('How do you stay creative under pressure?', 'Creativity is something I try to cultivate, but working under pressure can sometimes stifle it. I try to take short breaks and allow my mind to wander. How do you stay creative when working on tight deadlines or high-pressure projects?', 0, 'DISCUSSION', '2025-04-25 21:19:56', '2025-04-30 06:58:57', 12, 5),
                                                                                                        ('What’s the most valuable lesson you’ve learned in your career?', 'There are so many lessons I’ve learned, but the most valuable one is the importance of perseverance. I’ve faced many setbacks, but I’ve always managed to keep going. What’s the most valuable lesson you’ve learned in your career, and how has it shaped your journey?', 0, 'DISCUSSION', '2025-01-17 16:34:39', '2025-04-21 09:15:12', 14, 8);